create table users (id uuid primary key, email text unique, created_at timestamptz default now());
create table candidate_profiles (id uuid primary key, external_id text unique not null, user_id uuid references users(id), profile jsonb not null, created_at timestamptz default now(), updated_at timestamptz default now());
create index ix_candidate_profiles_user_id on candidate_profiles(user_id);
create table career_evidence (id uuid primary key, candidate_profile_id uuid not null references candidate_profiles(id) on delete cascade, source_type text not null, source_ref text, excerpt text not null, confidence numeric not null check (confidence >= 0 and confidence <= 1), claim_type text not null, claim_ref text not null);
create index ix_career_evidence_candidate_profile_id on career_evidence(candidate_profile_id);
create table profile_corrections (id uuid primary key, candidate_profile_id uuid not null references candidate_profiles(id) on delete cascade, field text not null, value jsonb not null, corrected_at timestamptz not null);
create index ix_profile_corrections_candidate_profile_id on profile_corrections(candidate_profile_id);
create table jobs (id text primary key, source text not null, source_url text unique not null, company text not null, title text not null, location text, description text not null, salary_min integer, salary_max integer, active boolean default true, raw jsonb, listing jsonb not null, fetched_at timestamptz default now(), constraint ck_jobs_salary_range check ((salary_min is null or salary_min >= 0) and (salary_max is null or salary_max >= 0) and (salary_min is null or salary_max is null or salary_min <= salary_max)));
create table job_matches (candidate_profile_id uuid references candidate_profiles(id) on delete cascade, job_id text references jobs(id) on delete cascade, scores jsonb not null, overall_score numeric not null check (overall_score >= 0 and overall_score <= 100), recommendation text not null check (recommendation in ('apply', 'consider', 'skip')), match jsonb not null, created_at timestamptz default now(), primary key(candidate_profile_id, job_id));
create index ix_job_matches_job_id on job_matches(job_id);
create table applications (id uuid primary key, application_key text unique not null, candidate_profile_id uuid not null references candidate_profiles(id), job_id text not null references jobs(id), package jsonb not null, status text not null check (status in ('prepared', 'approved', 'submitted', 'failed')), approved_at timestamptz, submitted_at timestamptz, created_at timestamptz default now());
create index ix_applications_candidate_profile_id on applications(candidate_profile_id);
create index ix_applications_job_id on applications(job_id);
create table consent_records (id uuid primary key, application_id uuid references applications(id), action text not null, consented_at timestamptz default now(), metadata jsonb);
